import json
import os
import subprocess
from google.cloud import storage
from urllib.parse import unquote_plus

def process_image(request):
    request_json = request.get_json(silent=True)
    
    if not request_json or 'bucket' not in request_json or 'name' not in request_json:
        return 'Invalid request', 400
    
    bucket_name = request_json['bucket']
    file_name = request_json['name']
    
    # Sanitize input to prevent path traversal
    file_name = os.path.basename(file_name)
    if not file_name:
        return 'Invalid filename', 400
    
    # Extract conversion options from metadata
    conversion_options = request_json.get('metadata', {}).get('conversion_options', '')
    
    # Validate conversion options to prevent command injection
    if not is_safe_conversion_options(conversion_options):
        return 'Invalid conversion options', 400
    
    # Download file from Cloud Storage
    storage_client = storage.Client()
    bucket = storage_client.bucket(bucket_name)
    blob = bucket.blob(file_name)
    
    # Create temporary local path
    temp_input_path = f'/tmp/{file_name}'
    temp_output_path = f'/tmp/processed_{file_name}'
    
    try:
        blob.download_to_filename(temp_input_path)
        
        # Build convert command with validation
        cmd = ['convert', temp_input_path]
        
        # Add conversion options if provided
        if conversion_options:
            options_list = conversion_options.split()
            # Validate each option
            for option in options_list:
                if not is_safe_option(option):
                    return 'Invalid conversion option', 400
            cmd.extend(options_list)
        
        # Add output path
        cmd.append(temp_output_path)
        
        # Execute convert command
        result = subprocess.call(cmd)
        
        if result != 0:
            return 'Image conversion failed', 500
        
        # Upload processed image back to Cloud Storage
        output_blob_name = f"processed_{file_name}"
        output_blob = bucket.blob(output_blob_name)
        output_blob.upload_from_filename(temp_output_path)
        
        # Clean up temporary files
        os.remove(temp_input_path)
        os.remove(temp_output_path)
        
        return 'Image processed successfully', 200
        
    except Exception as e:
        # Clean up temporary files on error
        try:
            os.remove(temp_input_path)
            os.remove(temp_output_path)
        except:
            pass
        return f'Error processing image: {str(e)}', 500

def is_safe_conversion_options(options):
    """Validate conversion options to prevent command injection"""
    if not options:
        return True
    
    # Allow only safe characters and common ImageMagick options
    allowed_chars = set('abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789_-.=/ ')
    return all(c in allowed_chars for c in options)

def is_safe_option(option):
    """Validate individual conversion option"""
    # Allow common ImageMagick options
    allowed_prefixes = ['-', '+', 'resize', 'quality', 'format', 'strip', 'interlace']
    
    if option.startswith(tuple(allowed_prefixes)):
        return True
    
    # Allow numeric values
    if option.replace('.', '').isdigit():
        return True
    
    # Allow common format specifiers
    if option in ['jpg', 'png', 'gif', 'webp']:
        return True
    
    return False